// ReconcileToClick coordinates the reconciliation of an install to a Facebook click claim
func (reconciler *Reconciler) Reconcile(
	ctx context.Context,
	wg *sync.WaitGroup,
	request *structs.WatsonRequest,
	claimChan chan<- waterfall.ClaimInterface,
	infChan chan<- waterfall.ClaimInterface,
	logChan chan<- reclog.Logger,
) {
	defer wg.Done()

	var ctxCancel context.CancelFunc
	ctx, ctxCancel = OncallCtxWithTimeout(ctx, request.App, request.TrafficType)

	defer func() {
		ctxCancel()
	}()

	match, log := reconciler.getFBClaimedInstall(ctx, request, infChan, logChan)

	if waterfall.IsClaimMatchAvailable(match) && match.GetAttributionModule() != "" {
		matchInterface := claimid.AddClaimID(match)
		claimChan <- matchInterface
		infChan <- matchInterface
	}

	logChan <- log
}

