func validatePayload(req *http.Request, watsonRequest *structs.WatsonRequest) (string, []byte, error) {
	//dec := json.NewDecoder(req.Body)
	//dec.DisallowUnknownFields()

	var msg string

	if req.Body == nil {
		// empty payload
		msg = "missing payload"
		return msg, []byte{}, errors.New(msg)
	}

	body, err := io.ReadAll(req.Body)
	if err != nil {
		return "cannot read the payload", body, err
	}

	if err = json.Unmarshal(body, watsonRequest); err != nil {
		//if err = dec.Decode(&watsonRequest); err != nil {

		var syntaxError *json.SyntaxError
		var unmarshalTypeError *json.UnmarshalTypeError
		var maxBytesError *http.MaxBytesError

		switch {
		case errors.As(err, &syntaxError):
			msg = fmt.Sprintf("request body contains badly-formed JSON (at position %d)", syntaxError.Offset)

		case errors.Is(err, io.ErrUnexpectedEOF):
			msg = "request body contains badly-formed JSON"

		case errors.As(err, &unmarshalTypeError):
			msg = fmt.Sprintf("request body contains an invalid value for the %q field (at position %d)",
				unmarshalTypeError.Field, unmarshalTypeError.Offset)

		case strings.HasPrefix(err.Error(), "json: unknown field "):
			fieldName := strings.TrimPrefix(err.Error(), "json: unknown field ")
			msg = fmt.Sprintf("request body contains unknown field %s", fieldName)

