// determineAttributionMethod maps the claim's attribution_module to the Facebook attribution method.
func determineAttributionMethod(claim waterfall.ClaimInterface) string {
	switch claim.GetAttributionModule() {
	case "facebook", "instagram":
		return "SRN"
	case "facebook-deeplink":
		return "DEEPLINK"
	case "facebook-install-referrer":
		return "GPIR"
	case "meta-install-referrer":
		return "MIR"
	default:
