func RestrictedLogResponse(watsonResponseChan chan *watson.Response, watsonResponse structs.WatsonResponse) error {
	protoLogItem, isRestricted, err := protoutil.RestrictedWatsonResponseToProto(watsonResponse)
	if err != nil {
		return fmt.Errorf("error converting watson struct to proto payload: %w", err)
	}
	if !isRestricted {
		return nil
	}

	watsonResponseChan <- protoLogItem

	return nil
}

